const parseJSON = (value, fallback) => {
  if (!value) return fallback;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
};

const getData = (key, fallback) => {
  return parseJSON(localStorage.getItem(key), fallback);
};

const setData = (key, data) => {
  localStorage.setItem(key, JSON.stringify(data));
};

const getNextId = (prefix) => {
  return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
};

const initStorage = () => {
  const users = getData(USERS_KEY, []);
  if (users.length === 0) {
    setData(USERS_KEY, defaultUsers);
  }

  const events = getData(EVENTS_KEY, []);
  if (events.length === 0) {
    setData(EVENTS_KEY, defaultEvents);
  }

  const registrations = getData(REGISTRATIONS_KEY, []);
  if (!Array.isArray(registrations)) {
    setData(REGISTRATIONS_KEY, []);
  }
};

const createResponse = (data) => ({ data });

export const registerUser = async (payload) => {
  initStorage();
  const users = getData(USERS_KEY, []);
  const normalizedEmail = payload.email.trim().toLowerCase();

  if (users.find((user) => user.email.toLowerCase() === normalizedEmail)) {
    throw new Error("User already exists");
  }

  const newUser = {
    id: getNextId("user"),
    name: payload.name,
    email: normalizedEmail,
    password: payload.password,
    role: "user",
    phone: payload.phone || "",
    college: payload.college || "",
    blocked: false,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  users.push(newUser);
  setData(USERS_KEY, users);
  return createResponse(newUser);
};

export const loginUser = async (payload) => {
  initStorage();
  const users = getData(USERS_KEY, []);
  const normalizedEmail = payload.email.trim().toLowerCase();
  const user = users.find(
    (user) => user.email.toLowerCase() === normalizedEmail && user.password === payload.password
  );

  if (!user) {
    throw new Error("Invalid credentials");
  }

  if (user.blocked) {
    throw new Error("User is blocked");
  }

  return createResponse(user);
};

export const fetchCurrentUser = async (id) => {
  initStorage();
  const users = getData(USERS_KEY, []);
  const user = users.find((item) => item.id === id);
  if (!user) {
    throw new Error("User not found");
  }
  return createResponse(user);
};

export const updateProfile = async (id, payload) => {
  initStorage();
  const users = getData(USERS_KEY, []);
  const userIndex = users.findIndex((item) => item.id === id);
  if (userIndex === -1) {
    throw new Error("User not found");
  }
  users[userIndex] = {
    ...users[userIndex],
    name: payload.name ?? users[userIndex].name,
    phone: payload.phone ?? users[userIndex].phone,
    college: payload.college ?? users[userIndex].college,
    updatedAt: new Date().toISOString()
  };
  setData(USERS_KEY, users);
  return createResponse(users[userIndex]);
};

